section.programlisting:
1 #ifndef HDEF_STRINGUTILS
2 #define HDEF_STRINGUTILS
3 
4 #include <string>
5 #include <algorithm>
6 
7 namespace Mochi::Utils
8 {
9     inline std::string NormalizePath(std::string path)
10     {
11         // Replace forward slashes with backslashes
12         std::replace(path.begin(), path.end(), '/', '\\');
13 
14         // Convert to lowercase
15         std::transform(path.begin(), path.end(), path.begin(),
16                        [](unsigned char c)
17                        { return std::tolower(c); });
18 
19         return path;
20     }
21 }
22 
23 #endif
